  "inlineSchema": "// Prisma schema for MangalyamMatch - Production Version\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = \"file:./dev.db\"\n}\n\nmodel User {\n  id            String @id @default(uuid())\n  email         String @unique\n  password_hash String\n\n  // Auth & Security\n  role       String    @default(\"USER\") // USER, ADMIN\n  status     String    @default(\"PENDING\") // ACTIVE, PENDING, BLOCKED\n  isVerified Boolean   @default(false)\n  otp        String?\n  otpExpires DateTime?\n\n  // Relations\n  profile           Profile?\n  sentInterests     Interest[] @relation(\"SentInterests\")\n  receivedInterests Interest[] @relation(\"ReceivedInterests\")\n\n  matches1 Match[] @relation(\"User1Matches\")\n  matches2 Match[] @relation(\"User2Matches\")\n\n  subscriptions Subscription[]\n  payments      Payment[]\n  reportsSent   Report[]       @relation(\"Reporter\")\n  reportsRec    Report[]       @relation(\"Reported\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Profile {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Basic info\n  name   String\n  about  String? // Added bio field\n  age    Int?\n  dob    DateTime?\n  gender String\n  height Int? // In cm\n\n  // Religion / Community\n  religion     String?\n  community    String?\n  subCommunity String?\n\n  // Demographics\n  education String?\n  job       String?\n  location  String?\n  city      String?\n  income    String?\n\n  // Lifestyle & Family\n  diet         String?\n  habits       String?\n  smoking      String?\n  drinking     String?\n  familyType   String?\n  familyValues String?\n\n  // Media\n  photos   String? // Comma-separated or JSON string\n  videoUrl String?\n\n  // Stats\n  trustScore Int     @default(0)\n  isPremium  Boolean @default(false)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Interest {\n  id         String @id @default(uuid())\n  senderId   String\n  receiverId String\n  status     String @default(\"PENDING\") // PENDING, ACCEPTED, DECLINED\n\n  sender   User @relation(\"SentInterests\", fields: [senderId], references: [id], onDelete: Cascade)\n  receiver User @relation(\"ReceivedInterests\", fields: [receiverId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\nmodel Match {\n  id      String @id @default(uuid())\n  user1Id String\n  user2Id String\n  status  String @default(\"ACTIVE\") // ACTIVE, UNMATCHED\n\n  user1 User @relation(\"User1Matches\", fields: [user1Id], references: [id], onDelete: Cascade)\n  user2 User @relation(\"User2Matches\", fields: [user2Id], references: [id], onDelete: Cascade)\n\n  messages Message[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([user1Id, user2Id])\n}\n\nmodel Message {\n  id       String  @id @default(uuid())\n  matchId  String\n  senderId String\n  content  String\n  isRead   Boolean @default(false)\n\n  match Match @relation(fields: [matchId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\nmodel Subscription {\n  id        String   @id @default(uuid())\n  userId    String\n  planType  String // FREE_TRIAL, BASIC, PREMIUM, SERIOUS\n  startDate DateTime @default(now())\n  endDate   DateTime\n  status    String   @default(\"ACTIVE\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel Payment {\n  id                String  @id @default(uuid())\n  userId            String\n  razorpayOrderId   String?\n  razorpayPaymentId String?\n  amount            Float\n  currency          String  @default(\"INR\")\n  status            String // PENDING, COMPLETED, FAILED\n\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n}\n\nmodel Report {\n  id         String @id @default(uuid())\n  reporterId String\n  reportedId String\n  reason     String\n  status     String @default(\"PENDING\") // PENDING, RESOLVED\n\n  reporter     User @relation(\"Reporter\", fields: [reporterId], references: [id], onDelete: Cascade)\n  reportedUser User @relation(\"Reported\", fields: [reportedId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n}\n\nmodel Admin {\n  id            String   @id @default(uuid())\n  username      String   @unique\n  password_hash String\n  level         Int      @default(1) // 1=Support, 2=Manager, 3=SuperAdmin\n  createdAt     DateTime @default(now())\n}\n",
